1	import { http, HttpResponse, JsonBodyType } from 'msw';
2	import { setupServer } from 'msw/node';
3	import { convertArrayToReadableStream } from './convert-array-to-readable-stream';
4	
5	export type UrlResponse =
6	  | {
7	      type: 'json-value';
8	      headers?: Record<string, string>;
9	      body: JsonBodyType;
10	    }
11	  | {
12	      type: 'stream-chunks';
13	      headers?: Record<string, string>;
14	      chunks: Array<string>;
15	    }
16	  | {
17	      type: 'binary';
18	      headers?: Record<string, string>;
19	      body: Buffer;
20	    }
21	  | {
22	      type: 'empty';
23	      headers?: Record<string, string>;
24	      status?: number;
25	    }
26	  | {
27	      type: 'error';
28	      headers?: Record<string, string>;
29	      status?: number;
30	      body?: string;
31	    }
32	  | {
33	      type: 'controlled-stream';
34	      headers?: Record<string, string>;
35	      controller: TestResponseController;
36	    }
37	  | undefined;
38	
39	type UrlResponseParameter =
40	  | UrlResponse
41	  | UrlResponse[]
42	  | ((options: { callNumber: number }) => UrlResponse);
43	
44	export type UrlHandler = {
45	  response: UrlResponseParameter;
46	};
47	
48	export type UrlHandlers<
49	  URLS extends {
50	    [url: string]: {
51	      response?: UrlResponseParameter;
52	    };
53	  },
54	> = {
55	  [url in keyof URLS]: UrlHandler;
56	};
57	
58	class TestServerCall {
59	  constructor(private request: Request) {}
60	
61	  get requestBodyJson() {
62	    return this.request!.text().then(JSON.parse);
63	  }
64	
65	  get requestBodyMultipart() {
66	    return this.request!.headers.get('content-type')?.startsWith(
67	      'multipart/form-data',
68	    )
69	      ? this.request!.formData().then(formData => {
70	          const entries: Record<string, any> = {};
71	          formData.forEach((value, key) => {
72	            entries[key] = value;
73	          });
74	          return entries;
75	        })
76	      : null;
77	  }
78	
79	  get requestCredentials() {
80	    return this.request!.credentials;
81	  }
82	
83	  get requestHeaders() {
84	    const requestHeaders = this.request!.headers;
85	
86	    const headersObject: Record<string, string> = {};
87	    requestHeaders.forEach((value, key) => {
88	      if (key.toLowerCase() === 'user-agent') return;
89	      headersObject[key] = value;
90	    });
91	
92	    return headersObject;
93	  }
94	
95	  get requestUserAgent(): string | undefined {
96	    return this.request!.headers.get('user-agent') ?? undefined;
97	  }
98	
99	  get requestUrlSearchParams() {
100	    return new URL(this.request!.url).searchParams;
101	  }
102	
103	  get requestUrl() {
104	    return this.request!.url;
105	  }
106	
107	  get requestMethod() {
108	    return this.request!.method;
109	  }
110	}
111	
112	export function createTestServer<
113	  URLS extends {
114	    [url: string]: {
115	      response?: UrlResponseParameter;
116	    };
117	  },
118	>(
119	  routes: URLS,
120	): {
121	  urls: UrlHandlers<URLS>;
122	  calls: TestServerCall[];
123	  server: { start: () => void; stop: () => void; reset: () => void };
124	} {
125	  const originalRoutes = structuredClone(routes);
126	
127	  const mswServer = setupServer(
128	    ...Object.entries(routes).map(([url, handler]) => {
129	      return http.all(url, ({ request }) => {
130	        const callNumber = calls.length;
131	
132	        calls.push(new TestServerCall(request));
133	
134	        const response =
135	          typeof handler.response === 'function'
136	            ? handler.response({ callNumber })
137	            : Array.isArray(handler.response)
138	              ? handler.response[callNumber]
139	              : handler.response;
140	
141	        if (response === undefined) {
142	          return HttpResponse.json({ error: 'Not Found' }, { status: 404 });
143	        }
144	
145	        const handlerType = response.type;
146	
147	        switch (handlerType) {
148	          case 'json-value':
149	            return HttpResponse.json(response.body, {
150	              status: 200,
151	              headers: {
152	                'Content-Type': 'application/json',
153	                ...response.headers,
154	              },
155	            });
156	
157	          case 'stream-chunks':
158	            return new HttpResponse(
159	              convertArrayToReadableStream(response.chunks).pipeThrough(
160	                new TextEncoderStream(),
161	              ),
162	              {
163	                status: 200,
164	                headers: {
165	                  'Content-Type': 'text/event-stream',
166	                  'Cache-Control': 'no-cache',
167	                  Connection: 'keep-alive',
168	                  ...response.headers,
169	                },
170	              },
171	            );
172	
173	          case 'controlled-stream': {
174	            if (request.signal) {
175	              request.signal.addEventListener('abort', () => {
176	                response.controller.error(
177	                  new DOMException('Aborted', 'AbortError'),
178	                );
179	              });
180	            }
181	
182	            return new HttpResponse(
183	              response.controller.stream.pipeThrough(new TextEncoderStream()),
184	              {
185	                status: 200,
186	                headers: {
187	                  'Content-Type': 'text/event-stream',
188	                  'Cache-Control': 'no-cache',
189	                  Connection: 'keep-alive',
190	                  ...response.headers,
191	                },
192	              },
193	            );
194	          }
195	
196	          case 'binary': {
197	            return HttpResponse.arrayBuffer(response.body, {
198	              status: 200,
199	              headers: response.headers,
200	            });
201	          }
202	
203	          case 'error':
204	            return HttpResponse.text(response.body ?? 'Error', {
205	              status: response.status ?? 500,
206	              headers: response.headers,
207	            });
208	
209	          case 'empty':
210	            return new HttpResponse(null, {
211	              status: response.status ?? 200,
212	            });
213	
214	          default: {
215	            const _exhaustiveCheck: never = handlerType;
216	            throw new Error(`Unknown response type: ${_exhaustiveCheck}`);
217	          }
218	        }
219	      });
220	    }),
221	  );
222	
223	  let calls: TestServerCall[] = [];
224	
225	  const start = () => {
226	    mswServer.listen();
227	  };
228	
229	  const reset = () => {
230	    mswServer.resetHandlers();
231	
232	    Object.entries(originalRoutes).forEach(([url, handler]) => {
233	      routes[url].response = handler.response;
234	    });
235	
236	    calls = [];
237	  };
238	
239	  const stop = () => {
240	    mswServer.close();
241	  };
242	
243	  return {
244	    urls: routes as UrlHandlers<URLS>,
245	    get calls() {
246	      return calls;
247	    },
248	    server: { start, stop, reset },
249	  };
250	}
251	
252	export class TestResponseController {
253	  private readonly transformStream: TransformStream;
254	  private readonly writer: WritableStreamDefaultWriter;
255	
256	  constructor() {
257	    this.transformStream = new TransformStream();
258	    this.writer = this.transformStream.writable.getWriter();
259	  }
260	
261	  get stream(): ReadableStream {
262	    return this.transformStream.readable;
263	  }
264	
265	  async write(chunk: string): Promise<void> {
266	    await this.writer.write(chunk);
267	  }
268	
269	  async error(error: Error): Promise<void> {
270	    await this.writer.abort(error);
271	  }
272	
273	  async close(): Promise<void> {
274	    await this.writer.close();
275	  }
