**OpenAI API Response Schema:**
```typescript
{
  created: number;
  data: Array<{
    b64_json: string;  // base64-encoded image
    revised_prompt?: string;  // OpenAI's optimized prompt
  }>;
  usage?: {
    input_tokens?: number;
    output_tokens?: number;
    total_tokens?: number;
    input_tokens_details?: {
      image_tokens?: number;
      text_tokens?: number;
    };
  };
  size?: string;
