124	  async doGenerate({
125	    prompt,
126	    n,
127	    size,
128	    aspectRatio,
129	    seed,
130	    providerOptions,
131	    headers,
132	    abortSignal,
133	    files,
134	    mask,
135	  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
136	    Awaited<ReturnType<ImageModelV3['doGenerate']>>
137	  > {
138	    const warnings: Array<SharedV3Warning> = [];
139	
140	    const backendConfig = modelToBackendConfig[this.modelId];
141	    if (!backendConfig?.supportsSize && size != null) {
142	      warnings.push({
143	        type: 'unsupported',
144	        feature: 'size',
145	        details:
146	          'This model does not support the `size` option. Use `aspectRatio` instead.',
147	      });
148	    }
149	
150	    // Use supportsSize as a proxy for whether the model does not support
151	    // aspectRatio. This invariant holds for the current set of models.
152	    if (backendConfig?.supportsSize && aspectRatio != null) {
153	      warnings.push({
154	        type: 'unsupported',
155	        feature: 'aspectRatio',
156	        details: 'This model does not support the `aspectRatio` option.',
157	      });
158	    }
159	
160	    // Handle files for image editing
161	    const hasInputImage = files != null && files.length > 0;
162	    let inputImage: string | undefined;
163	
164	    if (hasInputImage) {
165	      inputImage = convertImageModelFileToDataUri(files[0]);
166	
167	      if (files.length > 1) {
168	        warnings.push({
169	          type: 'other',
170	          message:
