87	export function createDeepInfra(
88	  options: DeepInfraProviderSettings = {},
89	): DeepInfraProvider {
90	  const baseURL = withoutTrailingSlash(
91	    options.baseURL ?? 'https://api.deepinfra.com/v1',
92	  );
93	  const getHeaders = () =>
94	    withUserAgentSuffix(
95	      {
96	        Authorization: `Bearer ${loadApiKey({
97	          apiKey: options.apiKey,
98	          environmentVariableName: 'DEEPINFRA_API_KEY',
99	          description: "DeepInfra's API key",
100	        })}`,
101	        ...options.headers,
102	      },
103	      `ai-sdk/deepinfra/${VERSION}`,
104	    );
105	
106	  interface CommonModelConfig {
107	    provider: string;
108	    url: ({ path }: { path: string }) => string;
109	    headers: () => Record<string, string>;
110	    fetch?: FetchFunction;
111	  }
112	
113	  const getCommonModelConfig = (modelType: string): CommonModelConfig => ({
114	    provider: `deepinfra.${modelType}`,
115	    url: ({ path }) => `${baseURL}/openai${path}`,
116	    headers: getHeaders,
117	    fetch: options.fetch,
118	  });
119	
120	  const createChatModel = (modelId: DeepInfraChatModelId) => {
121	    return new DeepInfraChatLanguageModel(
122	      modelId,
123	      getCommonModelConfig('chat'),
124	    );
125	  };
126	
127	  const createCompletionModel = (modelId: DeepInfraCompletionModelId) =>
128	    new OpenAICompatibleCompletionLanguageModel(
129	      modelId,
130	      getCommonModelConfig('completion'),
131	    );
132	
133	  const createEmbeddingModel = (modelId: DeepInfraEmbeddingModelId) =>
134	    new OpenAICompatibleEmbeddingModel(
135	      modelId,
136	      getCommonModelConfig('embedding'),
137	    );
138	
139	  const createImageModel = (modelId: DeepInfraImageModelId) =>
140	    new DeepInfraImageModel(modelId, {
141	      ...getCommonModelConfig('image'),
142	      baseURL: baseURL
143	        ? `${baseURL}/inference`
144	        : 'https://api.deepinfra.com/v1/inference',
145	    });
146	
147	  const provider = (modelId: DeepInfraChatModelId) => createChatModel(modelId);
148	
149	  provider.specificationVersion = 'v3' as const;
150	  provider.completionModel = createCompletionModel;
151	  provider.chatModel = createChatModel;
152	  provider.image = createImageModel;
153	  provider.imageModel = createImageModel;
154	  provider.languageModel = createChatModel;
155	  provider.embeddingModel = createEmbeddingModel;
156	  provider.textEmbeddingModel = createEmbeddingModel;
157	
158	  return provider;
159	}
