20	interface DeepInfraImageModelConfig {
21	  provider: string;
22	  baseURL: string;
23	  headers: () => Record<string, string>;
24	  fetch?: FetchFunction;
25	  _internal?: {
26	    currentDate?: () => Date;
27	  };
28	}
