150	  }),
151	});
152	
153	// limited version of the schema, focussed on what is needed for the implementation
154	// this approach limits breakages when the API changes and increases efficiency
155	export const deepInfraImageResponseSchema = z.object({
156	  images: z.array(z.string()),
157	});
158	
159	// Schema for OpenAI-compatible image edit endpoint errors
160	export const deepInfraEditErrorSchema = z.object({
161	  error: z
162	    .object({
163	      message: z.string(),
164	    })
165	    .optional(),
166	});
167	
